Rules.InvariantScript:
With(
    {
        SharedItemToPatch: LookUp(
            'Shared Equipment',
            ID = varRecord3.ItemBorrowed
        )
    },
    Patch(
        'Shared Equipment',
        SharedItemToPatch,
        {NumberOnLoan: SharedItemToPatch.NumberOnLoan - varRecord3.QTYBorrowed}
    )
);
Patch(
    'Equipment List Log',
    varRecord3,
    {
        Status: "Returned",
        DateActualReturn: Today()
    }
);
Set(
    varShowConfirm,
    false
);
